bool is_temperature_rising(int current, int previous)
{
    return (current > previous);
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = "STATE SAFE_OFF",
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        /* If temperature is above upper threshold, turn heater off */
        if (input.temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = "STATE SAFE_OFF";
            output.changed = true;
            return output;
        }

        /* If temperature is below low threshold, turn heater on */
        if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            controller_set_safe_off(controller);
            output.heater_on = true;
            output.state = CONTROLLER_STATE_HEATING;
            output.state_name = "STATE HEATING";
            output.changed = true;
            return output;
        }

        /* Temperature is in the holding range (47 <= TEMP < 50) */
        if (input.temperature_c >= CONTROLLER_TEMP_LOW_THRESHOLD && 
            input.temperature_c < CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Preserve previous safe actuator state for holding */
            controller_set_safe_off(controller);
            output.heater_on = false;
            output.state = CONTROLLER_STATE_HOLDING;
            output.state_name = "STATE HOLDING";
            output.changed = true;
            return output;
        }

        /* Temperature is in the early-off range (50 <= TEMP <= 52) */
        if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && 
            input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* Check if temperature is rising compared with previous valid sample */
            bool is_rising = false;

            if (controller->has_valid_sensor) {
                int prev_temp = controller->last_temperature_c;
                if (prev_temp > 0 && input.temperature_c > prev_temp) {
                    is_rising = true;
                }
            }

