                /* Early off due to rising temperature - treat as HOLDING */
                controller_set_safe_off(controller);
                output.heater_on = false;
                output.state = CONTROLLER_STATE_HOLDING;
                output.state_name = "STATE HOLDING";
                output.changed = true;
            } else {
                /* Not rising, hold the previous safe actuator state */
                controller_set_safe_off(controller);
                output.heater_on = false;
                output.state = CONTROLLER_STATE_HOLDING;
                output.state_name = "STATE HOLDING";
                output.changed = true;
